(36, 1, 'actas_entrega', 'CREATE', 20, NULL, '{\"id_usuario_tecnico\": 6, \"id_usuario_bodeguero\": 1, \"id_proyecto\": 2, \"tipo_acta\": \"ENTREGA_EPP\", \"estado_acta\": \"BORRADOR\", \"observaciones\": \"El cl\\u00e1sico logo de Securitas llevaba inmutable desde 1972. A pesar de que el cambio no ha sido radical, las modificaciones han afectado a varios elementos, incluyendo la tonalidad del color y la tipograf\\u00eda. La implementaci\\u00f3n de la \\u201cnueva marca\\u201d, no obstante, se ir\\u00e1 realizando de manera progresiva y gradual, comenzando por el escenario digital, que constituye una de las principales \\u00e1reas de acci\\u00f3n de la nueva estrategia. M\\u00e1s tarde, se extender\\u00e1 a los elementos f\\u00edsicos como los veh\\u00edculos y los uniformes.\", \"numero_acta\": \"ACT-B7F7A0D8\", \"detalles\": [{\"id_item\": 2, \"id_activo\": null, \"cantidad\": 1.0, \"notas_estado\": \"NUEVO\"}, {\"id_item\": 135, \"id_activo\": null, \"cantidad\": 1.0, \"notas_estado\": \"NUEVO\"}, {\"id_item\": 137, \"id_activo\": null, \"cantidad\": 1.0, \"notas_estado\": \"NUEVO\"}]}', '2026-05-31 20:18:38'),
