INSERT INTO `garantias` (`id_garantia`, `id_activo`, `id_proveedor`, `id_acta_devolucion`, `numero_caso_interno`, `rma_proveedor`, `numero_factura_compra`, `fecha_envio`, `fecha_limite_estimada`, `fecha_recibido_reparado`, `credenciales_equipo`, `area_origen`, `fecha_inicio_garantia`, `meses_garantia`, `tipo_resolucion`, `falla_reportada`, `comentarios_proceso`, `estado_proceso`) VALUES
(1, 2, 1, NULL, 'GSES-001', '2592', NULL, '2023-04-12', NULL, NULL, NULL, NULL, NULL, NULL, 'PENDIENTE', 'La bodycam no carga al ponerla en el dockstation.', NULL, 'ENVIADO_PROVEEDOR'),
(3, 635, NULL, NULL, 'GSES-000(PRUEBA 2)', '43525', 'FELE-160759', '2023-04-12', NULL, '2024-01-23', NULL, 'MANTENIMIENTO', NULL, NULL, 'PENDIENTE', 'Se realiza pruebas del disco el cual no lo reconoce y no inicializa, se prueba con grabador y con hdd docking.', '1,  se realizo el envio esperando garantia, 20 dias hábiles para respuesta.              2.se pide proceso de garantia y estamos pendientes de la respuesta 12/01/2024                 3. se recibe res´puesta y el equipo ya se envio a oficina de securitas hay que validar en recepcion cua do llegue el equipo', 'ENTREGADO_CLIENTE'),
(4, 636, NULL, NULL, 'GSES-000(PRUEBA 3)', 'RTV 34109485', 'FE16652', '2023-12-13', NULL, '2024-02-28', NULL, 'MANTENIMIENTO', NULL, NULL, 'PENDIENTE', 'Se realiza validacion de alimentacion y la camara no enciende, no recibe voltaje, pruebas en sitio y laboratorio puerto 13.', '1, esperando correo para envio                                                        2. enviar con las condiciones estabrecidad por el fabricante a oficina pelco                              3.se realizo el envio a SOKO del equipo esperamos pronta respuesta 13/12/2023                    4, Se solicita nuevamente informacion del como va el proceso, pendientes a respuesta del proveedor 12/01/2024                                 5. se recibe correo por parte del poveedor especificando que por temas vacaciones colectivas se suspendieron las garantias, ya retomaron las actividades y estan a la espera de validar el equipo.  6. se recibe correo por parte del proveedor que ls equipos hasta ahora van a llegar a miami 13/02/2024', 'ENTREGADO_CLIENTE'),
(5, 637, NULL, NULL, 'GSES-000(PRUEBA 4)', NULL, 'EFP 6818', NULL, NULL, '2024-02-26', NULL, 'MANTENIMIENTO', NULL, NULL, 'PENDIENTE', 'el cual se realizan pruebas en el expansor, se cierran todas las zonas con resistencia de 2k ohmios, se direcciona el expansor con la dirección número 8 en los dipswicths para usar la zona 16 y en el teclado se ven las fallas de la zona 16 para chequear y la zona 108 para tamper del expansor, esas zonas nunca restablecieron, se realizan las pruebas con la dirección número 10 en los dipswicths del expansor para usar la zona 33 y en esta segunda prueba se puede evidenciar que en el teclado las zonas 33 y 110 se encontraban abierta.', '1,solicitan video de la falla                   2, se realiza video y se entrega a proveedor.                                       3, se recibe correo para validar pruebas con asesoria del proveedor10/01/2024                       4.se habla por via telefonica con el porovvedor el cual indica que los equpos se demoran alrededor de 5 meses en llegar, no se acepto la nota credito a favor. 05/02/2024', 'ENTREGADO_CLIENTE'),
(6, 638, NULL, NULL, 'GSES-000(PRUEBA 5)', '10439', '342219', '2023-11-20', NULL, '2024-03-01', NULL, 'MANTENIMIENTO', NULL, NULL, 'PENDIENTE', 'Se intenta realizar la actualización de firmware y no es posible, se valida visual por red ingresa pero la pagina bloquea el ingreso por múltiples intentos de login, aun ya habiendo ingresado.', '1,  se realizo el envio esperando garantia .                  2. SINTOMA DETECTADO EN LABORATORIO:\n· Falla en la network board.\n\nACCION CORRECTIVA:\n· Requiere cambio de network board, cambio de MAC y mantenimiento preventivo.\nel equipo se encuentra en proceso de reparación, en cuanto se cuente con el en nuestras instalaciones se procedera con el envío.20/12/2023                         4. se entrega equipo a el laboratorio del SES, para realizar progranmacion.3/01/2024', 'ENTREGADO_CLIENTE'),
(7, 639, NULL, NULL, 'GSES-000(PRUEBA 6)', '10435', '329295', '2023-11-20', NULL, '2023-07-12', NULL, 'MANTENIMIENTO', NULL, NULL, 'PENDIENTE', 'Se deja el equipo conectado un largo tiempo pero en ningún momento hay comunicación con el panel.', '1,  se realizo el envio esperando garantia .', 'ENTREGADO_CLIENTE'),
(8, 641, NULL, NULL, 'GSES-002', 'GEO-20240125184', 'GV3202', '2024-01-25', NULL, '2024-05-02', NULL, 'MANTENIMIENTO', NULL, NULL, 'PENDIENTE', '1.Los dos equipos presentan falla en alimetacion PoE.                                              2. ELprovvedor valida que el equipo se encunetra fuera de garantia desde el da 10 de octubre de 2022', '1. se solicita a proveedor proceso de garantia el cual indica llenar formulario y hacer envio a la direccion especificada 19/01/2024            2.se recibe respuesta del proveedor el cual informa que los equipos estab fuera de garantia', 'ENTREGADO_CLIENTE'),
(9, 642, NULL, NULL, 'GSES-003', 'GEO-20240125183', 'GV3202', '2024-01-25', NULL, '2024-05-02', NULL, 'MANTENIMIENTO', NULL, NULL, 'PENDIENTE', '1.Los dos equipos presentan falla en alimetacion PoE.                                              2. ELprovvedor valida que el equipo se encunetra fuera de garantia desde el da 10 de octubre de 2022', '1. se solicita a proveedor proceso de garantia el cual indica llenar formulario y hacer envio a la direccion especificada 19/01/2024        2. se recibe respuesta del proveedor el cual informa que los equipos estab fuera de garantia', 'ENTREGADO_CLIENTE'),
(10, 643, NULL, NULL, 'GSES-005', '1085661', 'FA109739', '2024-02-02', NULL, '2024-02-19', NULL, 'MANTENIMIENTO', NULL, NULL, 'PENDIENTE', 'FALSAS ACTIVACIONES', '1. se realiza el envio del equipo a sede de syscom para la validacion de garantia 2/2/2024.                                2.se realiza comunicacion con SYSCOM e indican que los equipos estan en pruebas 9/2/2024                                      3.se recibe equipo nuevo por parte de SYSCOM', 'ENTREGADO_CLIENTE'),
(11, 644, NULL, NULL, 'GSES-006', '129578', '1 - 269502', '2024-02-02', NULL, '2024-06-02', NULL, 'MANTENIMIENTO', NULL, NULL, 'PENDIENTE', 'EL DISPOSITIVO NO TIENE ENFOQUE', '1. se inicia el procesos y 1. se realiza el envio del equipo a sede de gvs para la validacion de garantia 2/2/2024, esta pendiente la respuesta de correo por parte del proveedor para la RMA', 'ENTREGADO_CLIENTE'),
(12, 645, NULL, NULL, 'GSES-007', '02258003/918479', 'FELE-156833', '2024-07-29', NULL, '0000-00-00', NULL, 'SOLUICIONES', NULL, NULL, 'PENDIENTE', 'Se conecta al inyector POE y lo\npone en corto', '1. Se inicia el procesos y  se realiza el envio del equipo a sede de LINCE  para la validacion de garantia, se reciben equipos por parte de lince para realizar el proceso de garantia directamente con AXIS, se crea el caso en la PAG de AXIS y se espera repsuesta de paso aseguir del fabricante. 27/03/2024      2 .se esta a la espera de la importacion del equipo directamente no lo envia a sede principal de securitas 11/7/2024                                       3.se recibe correo de parte de axis notificando que el equipo se encuentra para recoger en la oficina de axis', 'ENTREGADO_CLIENTE'),
(13, 646, NULL, NULL, 'GSES-008', '02261182 /  923147', 'FELE-160224', '0000-00-00', NULL, '0000-00-00', NULL, 'SOLUICIONES', NULL, NULL, 'PENDIENTE', 'enciende pero no permite acceder\na la interfaz web', '1. Se inicia el procesos y  se realiza el envio del equipo a sede de LINCE  para la validacion de garantia, se reciben equipos por parte de lince para realizar el proceso de garantia directamente con AXIS, se crea el caso en la PAG de AXIS y se espera repsuesta de paso aseguir del fabricante. 27/03/2024      2 .s eests a la espera de la importacion del equipo directamente no lo envia a sede principal de securitas 11/7/2024', 'ENTREGADO_CLIENTE'),
(14, 647, NULL, NULL, 'GSES-009', '44310', 'FELE 170315', '2024-06-02', NULL, '0000-00-00', NULL, 'SOLUICIONES', NULL, NULL, 'PENDIENTE', 'Suena muy bajo', '1. Se inicia el procesos y se realiza el envio del equipo a sede de LINCE  para la validacion de garantia. 6/2/2024                               2.se recibe correo por parte del LINCE notificando los motivos por el cual se encuentra fuera de garantia. 9/2/2024', 'ENTREGADO_CLIENTE'),
(15, 648, NULL, NULL, 'GSES-010', '129786', '1-271882', '2024-06-02', NULL, '2024-02-21', NULL, 'SOLUICIONES', NULL, NULL, 'PENDIENTE', 'No enfoca, visual borrosa', '1. Se inicia el procesos y 1. se realiza el envio del equipo a sede de GVS para la validacion de garantia 2/2/2024, esta pendiente la respuesta de correo por parte del proveedor para la RMA.    3.se recibe respuesta favorble por parte del GVS y se esta a la espera de recoger el equipo.13/02/2024', 'ENTREGADO_CLIENTE'),
(16, 649, NULL, NULL, 'GSES-011', '44529', 'FELE-170889', '2024-02-23', NULL, '0000-00-00', NULL, 'MONITOREO', NULL, NULL, 'PENDIENTE', 'NO PERMITE EL REINICIO DE IP', '. Se inicia el procesos y se realiza el envio del equipo a sede de LINCE  para la validacion de garantia.                 2.se recibe correo por parte del proveedor en el que especifica que el equipo cumple garantia y sera remplazado por un equipo nuevo, se espera recibir los equipos que vienen de cali. 26/03/2024', 'ENTREGADO_CLIENTE'),
(17, 650, NULL, NULL, 'GSES-012', '130243', '267693', '2024-02-21', NULL, '2024-03-05', NULL, 'SOLUICIONES', NULL, NULL, 'PENDIENTE', 'falla en conector, mal tapar la camara pierde video, posible daño en el cablerado interno.', '1. Se inicia el procesos y 1. se realiza el envio del equipo a sede de GVS para la validacion de garantia .                 2.se recibe correo del proovedor notificando que el equipo esta fuera de garantia por mala manipulacion. se realiza proceso y espera de persnal para recoger el equipo en GVS. 29/02/2024', 'ENTREGADO_CLIENTE'),
(18, 651, NULL, NULL, 'GSES-013', '44503', 'FELE-168204', '2024-02-19', NULL, '0000-00-00', NULL, 'SOLUICIONES', NULL, NULL, 'PENDIENTE', 'Se calienta la placa principal, no permite manipular la alarma', '1. Se inicia el procesos y se realiza el envio del equipo a sede de LINCE  para la validacion de garantia. 19/2/2024                               2.se recibe correo por parte del LINCE notificando los motivos por el cual se encuentra fuera de garantia. 22/2/2024                                    3. Se Recibe  los equipos por parte de LINCE y se valida con el Ing que se dispone con el equipos', 'ENTREGADO_CLIENTE'),
(19, 652, NULL, NULL, 'GSES-014', '44528', 'FELE - 159709', '2024-02-23', NULL, '2024-03-05', NULL, 'MONITOREO', NULL, NULL, 'PENDIENTE', 'No perminte hacer el registro o vincularse  en panel', '1. Se inicia el procesos y se realiza el envio del equipo a sede de LINCE  para la validacion de garantia. 19/2/2024                                   2. Se recibe correo por parte del LINCE notificando los motivos por el cual se encuentra fuera de garantia. 26/2/2024.                                3. se recibe equipo nuevo por parte de garantia y correo de confirmacion con el reporte tecnico 5/3/2024', 'ENTREGADO_CLIENTE'),
(20, 653, NULL, NULL, 'GSES-015', '21074', 'COM26814', '2024-02-28', NULL, '2024-11-03', NULL, 'MANTENIMIENTO', NULL, NULL, 'PENDIENTE', 'El EQUIPO SE RECONOCE, SE DEJA REINICIAR, SE DE JA CONFIGURAR PERO NO SE CONECTA CON NINGUN RADIO ENLACE.', '1. Se inicia el procesos y se realiza el envio del equipo a sede de MELTEC  para la validacion de garantia. 28/2/2024                                   2. Se recibe correo por parte delMELTEC notificando la recepcion de los equipos 28/02/24                                       3.se recibe correo por parte del proveedor dando disposicion  del equipo en garantia, se relaiza la reparacion del equipo. y envian correo con soporte de la garanta 8/03/2024', 'REGISTRADO'),
(21, 654, NULL, NULL, 'GSES-016', '44567', 'FELE - 139710', '2024-02-26', NULL, '2024-03-04', NULL, 'MANTENIMIENTO', NULL, NULL, 'PENDIENTE', 'EL EQUIPO SE ENCUNTRA EN CORTO', '1. Se inicia el procesos y se realiza el envio del equipo a sede de LINCE  para la validacion de garantia. 19/2/2024                                   2. Se recibe correo por parte del LINCE notificando los motivos por el cual se encuentra fuera de garantia. 26/2/2024.                                3.se recibe el equipo y correo con el diagnostico fuera de garantia del equipo. 04/03/2024', 'ENTREGADO_CLIENTE'),
(22, 655, NULL, NULL, 'GSES-017', '44566', 'FELE - 139710', '2024-02-26', NULL, '2024-03-04', NULL, 'MANTENIMIENTO', NULL, NULL, 'PENDIENTE', 'SE SUMINISTRA VOLTAJE Y EL EQUIPO NO ENCIENDE', '1. Se inicia el procesos y se realiza el envio del equipo a sede de LINCE  para la validacion de garantia. 19/2/2024                                   2. Se recibe correo por parte del LINCE notificando los motivos por el cual se encuentra fuera de garantia. 26/2/2024.                                3.se recibe el equipo y correo con el diagnostico fuera de garantia del equipo. 04/03/2024', 'ENTREGADO_CLIENTE'),
(23, 656, NULL, NULL, 'GSES-018', '1086132', 'CE1001', '2024-03-22', NULL, '2024-11-04', NULL, 'MANTENIMIENTO', NULL, NULL, 'PENDIENTE', 'FALSAS ACTIVACIONES', '1. se inicia el proceso de garanti a la espera de personal del SES para realizar envio del equipo a sede de syscom para la validacion de garantia.                                    2.se realiza envio del equipo al proveedor por parte de personla de secutitas 22/03/2024', 'ENTREGADO_CLIENTE'),
(24, 657, NULL, NULL, 'GSES-020', '3349', 'BOG1193321', '2024-10-04', NULL, '2024-04-29', NULL, 'INSTALACIONES', NULL, NULL, 'PENDIENTE', 'EL EQUIPO HIXVISION EN HORARIO \nNOCTURNO, PRESENTA FALLO EN \nLA VISUAL, SE EVIDENCIAN \nCOLORES EXTRAÑOS Y \nDESFASADOS', '1. Se inicia proceso de garantia, a espera dela llegada de los equipos a sede principal para validacion y envio a proveedor MEM          2.se recibe correo por parte de personal de securitas bucaramanga en el cual se indica la guia de envio del equipo a sede pricipal en bogota. 27/03/24                     3.se recibe la camara y se tramita la cgarantia en `pagina de MEM a espera del No de garantia ara realizar el envio a punto de proveedor 05/04/2024                                 4.se recibe correo de proveedor para realizar el envio del equipo a sede puente aranda 08/04/2024   5.Se realiza el envio al proveedorcon auxiliar tecnico y se recibio correo por parte de mem validando numero de caso 10/04/2024                           5. se recibe correo por parte MEM dando solcuoion satisfactoria de la garantia a espera de llegada de garantia a la oficina', 'ENTREGADO_CLIENTE'),
(25, 658, NULL, NULL, 'GSES-021', '2223003', 'FELE-77770', '0000-00-00', NULL, '2024-02-04', NULL, 'MANTENIMIENTO', NULL, NULL, 'PENDIENTE', 'Falla en grabacion, se pierde calidad de imagen y muy baja resolucoin en grabaciones.', '1. se inicia el proceso de garantia y se deja la camara en supervision en laboratorio y se espera factura para realizar el proceso respectivo,con el porvvedor correspondiente o si cumple los parametros de garantia, 27/03/2024                                2.se recibe correo por parte del fabricante el cual indica que los equipos se ecnuntra fuera de garantia por tiempo.02/04/2024', 'REGISTRADO'),
(26, 659, NULL, NULL, 'GSES-022', '44992', 'FELE-167076', '2024-01-04', NULL, '2024-09-05', NULL, 'MONITOREO', NULL, NULL, 'PENDIENTE', 'DAÑOS  FISICOS EN LA TARJETA', '1. Se inicial el proceso de garantia con el proveedor LINCE y se esta a la espera de enviar el dia lunes el equipo a sedecali para vlaidacion de garantia. 27/03/2024                     2.se  recibe correo electronico con recibiemiento de equipo en sede de proveedor 16/04/2024             3. tajeta cpm daños el cualno aplica garantia pero se realiza el arreglo por unica vez. el equipo se envia sede securitas, esperando llegada', 'REGISTRADO'),
(27, 660, NULL, NULL, 'GSES-023', NULL, 'FELE-152096', '0000-00-00', NULL, '2024-04-15', NULL, 'MANTENIMIENTO', NULL, NULL, 'PENDIENTE', 'PERDIDA DE ENERGIA CONSTANTE, SE REINICIA', '1. se recibio el equipò y se realizaron pruebas las cuales no presentan ninguna falla, deben revisar fuentes de alimentacion y cableado se deja notificado a yilver via correo electronico para paso a seguir.', 'ENTREGADO_CLIENTE'),
(28, 661, NULL, NULL, 'GSES-024', '45103', 'FELE-172412', '2024-11-04', NULL, '2024-09-05', NULL, 'b', NULL, NULL, 'PENDIENTE', 'Dejo de funcionar sin razon aparente, al reemplazar el equipo, la fibra opero con normalidad, tener en cuenta que se tienen 9 conversores en la misma ubicación', '1. Se inicia el procesos y se realiza el envio del equipo a sede de LINCE  para la validacion de garantia. 11/04/2024                                       2.se recibe correo de lince con la confirmacion del cambio de equipo en garantia por uno nuevo, a espera de arribo a  sede securitas 2/5/2024', 'ENTREGADO_CLIENTE'),
(29, 662, NULL, NULL, 'GSES-025', '45321', 'CONT 10.096', '2024-04-29', NULL, '2024-11-05', NULL, 'MONITOREO', NULL, NULL, 'PENDIENTE', 'EQUIPO NO ENCIENDE', '1. Se inicia el procesos y se realiza el envio del equipo a sede de LINCE para la validacion de garantia. 29/4/2024                                    2.se recibe correo por parte LINCE confirmando llegada del equipo de garantia', 'ENTREGADO_CLIENTE'),
(30, 663, NULL, NULL, 'GSES-027', '21871', 'COM22256', '2024-05-10', NULL, '2024-10-07', NULL, 'MANTENIMIENTO', NULL, NULL, 'PENDIENTE', 'No conecta en red', '1. Se inicia el procesos y se realiza el envio del equipo a sede de MELTEC  para la validacion de garantia.  09/05/2024                                2.se recibe correo con la recepcion de los equipos donde el proveedor, se espera notificacion por el proceso por 15 dias habiles.10/5/2024                     3. Se envia correo con solcitud de avvance en el proceso del cual no se recibe respuesta,                                   4.se recibe correo por parte de MELTEC el cual indica realizar nota credito al contar coninconvenientes de respuesta por parte del fabricante', 'ENTREGADO_CLIENTE'),
(31, 664, NULL, NULL, 'GSES-028', '479424', 'gs01-00045441', '2024-05-23', NULL, '2024-06-19', NULL, 'MANTENIMIENTO', NULL, NULL, 'PENDIENTE', 'EQUIPO SIN DETECCION DE GRABADORES, NO SE CONECTA', '1. se inicia el proceso de GARANTIA y se realiza envio del equipo a sede de GSP  para la validacion de garantia.                                     2. el prooveedor indica via correo electronico quie la garantia fue resuelta yt se puede pasar por el equipo a sede de gsp', 'ENTREGADO_CLIENTE'),
(32, 665, NULL, NULL, 'GSES-029', '45851', 'FELE-164332', '2024-05-28', NULL, '2024-08-21', NULL, 'SOLUICIONES', NULL, NULL, 'PENDIENTE', 'LA CAMARA EN EXTERIOR PRESENTA EMPAÑAMIENTO INTERNO EN EL LENTE.', '1. Se inicia el procesos y se realiza el envio del equipo a sede de LINCE  para la validacion de garantia.            2. se recibe correo con recepcion del equipo y con numero de caso asignado por parte del proveedor30/5/2025 7/6/2024 equipo no cuenta con garantia pero se realiza mantenimiento, a la espera del equipo en cuanto se traiga otra garantia.', 'ENTREGADO_CLIENTE'),
(33, 666, NULL, NULL, 'GSES-030', 'GEO-20240612282', 'GV 4153', '0000-00-00', NULL, '2024-08-13', NULL, 'INSTALACIONES', NULL, NULL, 'PENDIENTE', 'Daño en el Puerto PoE', '1. se realizo el envio de la camara a geovision.                        2. se recibe respuesta por parte del proeevdotr el cual indica que el equipo esta en proceso.                                        3. se recibe correo notificando que la enrega del equipo estara entreb el 7 y 9 de agosto 26/07/2027', 'ENTREGADO_CLIENTE'),
