--
-- Estructura para la vista `v_dashboard_kpis`
--
DROP TABLE IF EXISTS `v_dashboard_kpis`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `v_dashboard_kpis`  AS SELECT (select count(0) from `activos` where `activos`.`estado_actual` = 'DISPONIBLE') AS `activos_disponibles`, (select count(0) from `activos` where `activos`.`estado_actual` = 'INSTALADO') AS `activos_instalados`, (select count(0) from `activos` where `activos`.`estado_actual` = 'LABORATORIO') AS `activos_laboratorio`, (select count(0) from `activos` where `activos`.`estado_actual` = 'EN_GARANTIA') AS `activos_garantia`, (select count(0) from `garantias` where `garantias`.`estado_proceso` <> 'ENTREGADO_CLIENTE') AS `garantias_abiertas`, (select count(0) from `proyectos` where `proyectos`.`estado` = 'ACTIVO') AS `proyectos_activos`, (select count(0) from (`stock_bulk` `sb` join `items` `i` on(`sb`.`id_item` = `i`.`id_item`)) where `sb`.`cantidad_actual` <= `i`.`stock_minimo`) AS `items_bajo_minimo`, (select count(0) from `usuarios` where `usuarios`.`is_active` = 1) AS `usuarios_activos` ;

-- --------------------------------------------------------

--
-- Estructura para la vista `v_stock_consolidado`
--
DROP TABLE IF EXISTS `v_stock_consolidado`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `v_stock_consolidado`  AS SELECT `i`.`id_item` AS `id_item`, `i`.`nombre_equipo` AS `nombre_equipo`, `i`.`marca` AS `marca`, `i`.`referencia` AS `referencia`, `i`.`categoria` AS `categoria`, `i`.`stock_minimo` AS `stock_minimo`, coalesce(sum(case when `a`.`estado_actual` = 'DISPONIBLE' then 1 else 0 end),0) AS `stock_activos_disponibles`, coalesce(`sb`.`cantidad_actual`,0) AS `stock_bulk_actual`, CASE WHEN coalesce(`sb`.`cantidad_actual`,0) <= `i`.`stock_minimo` THEN 1 ELSE 0 END AS `alerta_recompra` FROM ((`items` `i` left join `activos` `a` on(`i`.`id_item` = `a`.`id_item`)) left join `stock_bulk` `sb` on(`i`.`id_item` = `sb`.`id_item`)) GROUP BY `i`.`id_item`, `i`.`nombre_equipo`, `i`.`marca`, `i`.`referencia`, `i`.`categoria`, `i`.`stock_minimo`, `sb`.`cantidad_actual` ;

